for name,content in FILES.items():
    target=root/name
    target.parent.mkdir(parents=True,exist_ok=True)
    if target.exists():
        saved=backup/name
        saved.parent.mkdir(parents=True,exist_ok=True)
        saved.write_bytes(target.read_bytes())
    target.write_text(content,encoding="utf-8")
